import requests
import json

def create_service(name):
    url = 'http://localhost:8001/services/{}'.format(name)
    payload = {
        "url": "http://{}.com".format(name),
        "protocol": "http",
        "port": 80,
        "path": "/"
    }
    
    headers = {'Content-Type': 'application/json'}
    
    response = requests.post(url, data=json.dumps(payload), headers=headers)
    
    if response.status_code == 201:
        print("Service {} created successfully".format(name))
    else:
        print("Failed to create service {}. Received status code {}".format(name, response.status_code))

def create_route(service, route_name):
    url = 'http://localhost:8001/services/{}/routes'.format(service)
    payload = {"paths": ["/"], "methods": ["GET", "POST"]}
    
    headers = {'Content-Type': 'application/json'}
    
    response = requests.post(url, data=json.dumps(payload), headers=headers)
    
    if response.status_code == 201:
        print("Route {} for service {} created successfully".format(route_name, service))
    else:
        print("Failed to create route {}. Received status code {}".format(route_name, response.status_code))
        
def create_upstream(service, upstream_name):
    url = 'http://localhost:8001/services/{}/upstreams'.format(service)
    payload = {"targets": [{"target": "127.0.0.1", "weight": 1}]}
    
    headers = {'Content-Type': 'application/json'}
    
    response = requests.post(url, data=json.dumps(payload), headers=headers)
    
    if response.status_code == 201:
        print("Upstream {} for service {} created successfully".format(upstream_name, service))
    else:
        print("Failed to create upstream {}. Received status code {}".format(upstream_name, response.status_code))